const person = {
    name: 'John',
    age: 30,
    city: 'New York',
    GeolocationCoordinates: function() {
        // Implementation for GeolocationCoordinates
        return { latitude: 40.7128, longitude: -74.0060 };  
    }   
};

//Accessing properties using dot notation
console.log(person.name); // Output: 'John'
console.log(person.age); // Output: 30
console.log(person.city); // Output: 'New York'
console.log(person.GeolocationCoordinates()); // Output: { latitude: 40.7128, longitude: -74.0060 } 

//Destructuring 
const {name, city } = person;
console.log(name, city); // "John" "New York"

//Spread (shallow copy + merge)
const updated = {...person, age:31, country:"US"};

//Object utility methods

// Using Object.keys() to get an array of property names
const keys = Object.keys(person);
console.log(keys); // Output: ['name', 'age', 'city']       
// Using Object.values() to get an array of property values
const values = Object.values(person);
console.log(values); // Output: ['John', 30, 'New York']
// Using Object.entries() to get an array of [key, value] pairs
const entries = Object.entries(person);
console.log(entries); // Output: [['name', 'John'], ['age', 30], ['city', 'New York']]      

const frozenPerson = Object.freeze(person);
frozenPerson.name = 'Jane'; 
console.log(frozenPerson.name); // Output: 'John' (the name property cannot be modified)

const sealedPerson = Object.seal(person);
delete sealedPerson.age; 
console.log(sealedPerson.age); // Output: 30 (the age property cannot be deleted)   
Object.preventExtensions(person);
person.country = 'USA'; 
console.log(person.country); // Output: undefined (new properties cannot be added)  
const obj1 = { a: 1 };
const obj2 = { b: 2 };
const mergedObj = Object.assign({}, obj1, obj2);
console.log(mergedObj); // Output: { a: 1, b: 2 }  


